INSERT INTO map_markers (id, map_id, x_pct, y_pct, label, plant_name, living_beings, note, emoji, created_at) VALUES ('f9b4f4f0-2c21-4f00-a6d7-ca41b4e1e606', 'foret', 61.19109945802678, 86.1922688453388, 'Ruches', '', NULL, 'Les abeilles sont des insectes pollinisateurs essentiels à la biodiversité, vivant en colonies organisées dans des ruches.\nElles jouent un rôle crucial en butinant le nectar et le pollen des fleurs, permettant la reproduction des plantes et la production de fruits et légumes.', '🐝', '2026-03-15 18:34:36');
